solution: class Solution {
public:
    static constexpr int MOD = 1'000'000'007;
    int countKReducibleNumbers(string s, int k) {
        int m = (int)s.size();
        if (m == 1) return 0;

        vector<int> steps(1 << 14);
        for (int i = 2; i < (1 << 14); ++i) {
            steps[i] = steps[__builtin_popcount(i)] + 1;
        }

        int maxPop = m;
        vector<long long> dp(maxPop + 1, 0);
        dp[0] = 1;
        for (int i = 0; i < m; ++i) {
            vector<long long> ndp(maxPop + 1, 0);
            for (int j = 0; j <= maxPop; ++j) {
                if (dp[j] == 0) continue;
                ndp[j] = (ndp[j] + dp[j]) % MOD;
                if (j + 1 <= maxPop) {
                    ndp[j + 1] = (ndp[j + 1] + dp[j]) % MOD;
                }
            }
            if (s[i] == '0') {
                for (int j = 0; j <= maxPop; ++j) {
                    if (j) ndp[j - 1] = (ndp[j - 1] - dp[j] + MOD) % MOD;
                }
            }
            dp.swap(ndp);
        }

        long long ans = 0;
        for (int pop = 1; pop <= maxPop; ++pop) {
            if (steps[pop] < k) {
                ans = (ans + dp[pop]) % MOD;
            }
        }
        return (int)ans;
    }
};
